function resolveTopicKey(_slug: string, topicTitle: string): string {
  const normalized = normalizeOutlineKey(topicTitle);
  return TOPIC_ALIASES[normalized] ?? normalized;
}

export function getModuleDescription(
  slug: string,
  quarterIndex: number,
  moduleIndex: number,
  _moduleTitle?: string,
): string | undefined {
  return MODULE_DESCRIPTIONS[slug]?.[quarterIndex]?.[moduleIndex];
}

export function getTopicDescription(
  slug: string,
  topicTitle: string,
  _moduleTitle?: string,
  quarterIndex?: number,
  moduleIndex?: number,
): string | undefined {
  const key = resolveTopicKey(slug, topicTitle);
  if (quarterIndex !== undefined && moduleIndex !== undefined) {
    const scoped =
      SCOPED_TOPIC_DESCRIPTIONS[slug]?.[`${quarterIndex}:${moduleIndex}:${key}`];
    if (scoped) return scoped;
  }
  const direct = TOPIC_DESCRIPTIONS[slug]?.[key];
  if (direct) return direct;
  if (/project/i.test(topicTitle)) return PROJECT_DESCRIPTION;
  return undefined;
}

export function enrichOutlineFromCopy<
  T extends {
    modules: Array<{
      title: string;
      description?: string;
      topics: Array<{ title: string; description?: string }>;
    }>;
  },
>(slug: string, quarters: T[], quarterOffset = 0): T[] {
  return quarters.map((quarter, quarterIndex) => ({
    ...quarter,
    modules: quarter.modules.map((module, moduleIndex) => ({
      ...module,
      description:
        getModuleDescription(slug, quarterIndex + quarterOffset, moduleIndex, module.title) ??
        module.description ??
        '',
      topics: module.topics.map((topic) => ({
        ...topic,
        description:
          getTopicDescription(
            slug,
            topic.title,
            module.title,
            quarterIndex + quarterOffset,
            moduleIndex,
          ) ??
          topic.description ??
          '',
      })),
    })),
  }));
}
